import{_ as e}from"./chunks/Pin24Regular.BSysiH1_.js";import{_ as i}from"./chunks/ArrowExpand24Regular.8iD4AueM.js";import{_ as l,c as a,o as r,a3 as d}from"./chunks/framework.CTM16EAR.js";const t="/pomotention/pomodoro-mode.png",c="/pomotention/pizza-mode.png",P=JSON.parse('{"title":"番茄时钟使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reference/timer.md","filePath":"guide/reference/timer.md","lastUpdated":1778145274000}'),n={name:"guide/reference/timer.md"};function s(m,o,h,p,u,g){return r(),a("div",null,o[0]||(o[0]=[d('<h1 id="番茄时钟使用说明" tabindex="-1">番茄时钟使用说明 <a class="header-anchor" href="#番茄时钟使用说明" aria-label="Permalink to &quot;番茄时钟使用说明&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>与其他区域的协作关系见 <a href="./workflow.html">模块联动</a>。</p></div><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><ul><li>我想用单次计时：见 <a href="#单次计时模式-pomodoro-mode">单次计时模式</a></li><li>我想配置连续序列：见 <a href="#连续计时模式-pizza-mode">连续计时模式</a></li><li>我想使用简洁悬浮窗口：见 <a href="#迷你计时器模式-on-top-mode">迷你计时器模式</a></li><li>我想看限制条件：见 <a href="#限制与说明">限制与说明</a></li></ul><h2 id="单次计时模式-pomodoro-mode" tabindex="-1">单次计时模式 (Pomodoro Mode) <a class="header-anchor" href="#单次计时模式-pomodoro-mode" aria-label="Permalink to &quot;单次计时模式 (Pomodoro Mode)&quot;">​</a></h2><p>适用于单次专注或单次休息。<br><img src="'+t+'" alt="Pomodoro Mode" width="200"></p><ul><li><strong>开始工作</strong>：点击 <code>Wind up</code> 启动工作周期。</li><li><strong>取消工作</strong>：点击 <code>Squash</code> 终止当前工作计时。</li><li><strong>开始休息</strong>：点击 <code>Break</code> 启动休息计时。</li><li><strong>结束休息</strong>：点击 <code>Stop</code> 可提前结束休息。</li><li><strong>调整休息时长</strong>：支持 <code>02</code> / <code>05</code> / <code>10</code> / <code>15</code> / <code>30</code> / <code>60</code> 分钟。</li></ul><h3 id="声音提示节奏-25-分钟示例" tabindex="-1">声音提示节奏（25 分钟示例） <a class="header-anchor" href="#声音提示节奏-25-分钟示例" aria-label="Permalink to &quot;声音提示节奏（25 分钟示例）&quot;">​</a></h3><ul><li>工作开始提示；</li><li><code>Review</code> 阶段（2 分钟）提示；</li><li>两段 <code>Work</code> 阶段（各约 10.5 分钟）提示；</li><li><code>Review</code> 阶段（1 分钟）提示；</li><li><code>Track</code> 阶段（1 分钟）无声音提示；</li><li>周期结束提示。</li></ul><h3 id="休息提示" tabindex="-1">休息提示 <a class="header-anchor" href="#休息提示" aria-label="Permalink to &quot;休息提示&quot;">​</a></h3><ul><li>开始；</li><li>1/5；</li><li>2/5；</li><li>3/5；</li><li>结束。</li></ul><h2 id="连续计时模式-pizza-mode" tabindex="-1">连续计时模式 (Pizza Mode) <a class="header-anchor" href="#连续计时模式-pizza-mode" aria-label="Permalink to &quot;连续计时模式 (Pizza Mode)&quot;">​</a></h2><p>适用于多个工作/休息周期连续执行。<br><img src="'+c+'" alt="Pizza Mode" width="200"></p><ul><li><strong>模式切换</strong>：点击 🍅🍕 切换单次/连续模式；运行中不可切换。</li><li><strong>自定义序列</strong>：在输入框中填写序列指令： <ul><li><code>🍅+05</code>：一个工作周期后自动休息 5 分钟。</li><li><code>05+05</code>：连续两个 5 分钟休息段。</li></ul></li><li><strong>修改默认工作时长</strong>：通过 <code>🍅=25min</code> 调整，支持 <code>15min</code> 到 <code>59min</code>。</li><li><strong>白噪音</strong>：点击 🔈 开关背景音，点击红点切换滴答/雨声。</li></ul><h2 id="迷你计时器模式-on-top-mode" tabindex="-1">迷你计时器模式 (On top Mode) <a class="header-anchor" href="#迷你计时器模式-on-top-mode" aria-label="Permalink to &quot;迷你计时器模式 (On top Mode)&quot;">​</a></h2><p>为低干扰专注场景设计：</p><ol><li>点击菜单栏 <img src="'+e+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(224, 224, 224);border-radius:6px;"> 进入置顶迷你模式。</li><li>点击计时器界面 <img src="'+i+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;"> 退出迷你模式。</li><li>支持多实例同时运行，并可分别设置是否迷你显示。</li><li>macOS 可结合 Sidecar 将迷你计时器放到 iPad 等扩展屏。</li></ol><h2 id="限制与说明" tabindex="-1">限制与说明 <a class="header-anchor" href="#限制与说明" aria-label="Permalink to &quot;限制与说明&quot;">​</a></h2><ul><li>计时运行时不能切换 <code>单次/连续</code> 模式。</li><li>某些平台可能偶发窗口尺寸计算异常，重新进入迷你模式可触发自动修正。</li></ul>',19)]))}const k=l(n,[["render",s]]);export{P as __pageData,k as default};
